import React, { useState, useEffect } from 'react';
import axios from 'axios';

const AdminPanel = () => {
  const [activeTab, setActiveTab] = useState('create'); 
  const [postType, setPostType] = useState('blog'); 
  const [category, setCategory] = useState('Electronics');
  const [formData, setFormData] = useState({ title: '', description: '', loc: '', salary: '', type: 'On-site' });
  const [file, setFile] = useState(null);
  const [items, setItems] = useState([]); 
  const [inquiries, setInquiries] = useState([]); // State for Contact Data

  const [isEditing, setIsEditing] = useState(false);
  const [editData, setEditData] = useState(null);

  // 1. Fetch Contact Inquiries
  const fetchInquiries = async () => {
    try {
      const res = await axios.get('http://localhost:5001/api/contact');
      setInquiries(res.data);
    } catch (err) { console.error("Inquiries fetch failed", err); }
  };

  // 2. Fetch Blog/Job Items
  const fetchItems = async () => {
    try {
      const url = postType === 'job' 
        ? 'http://localhost:5001/api/jobs' 
        : `http://localhost:5001/api/blog/${category}`;
      const res = await axios.get(url);
      setItems(res.data);
    } catch (err) { console.error(err); }
  };

  useEffect(() => {
    if (activeTab === 'manage') fetchItems();
    if (activeTab === 'inquiries') fetchInquiries();
  }, [activeTab, postType, category]);

  const handleUpdate = async (e) => {
    e.preventDefault();
    try {
      const endpoint = postType === 'job' ? 'jobs' : 'blog';
      await axios.patch(`http://localhost:5001/api/admin/${endpoint}/${editData._id}`, editData);
      alert("Updated Successfully!");
      setIsEditing(false);
      fetchItems();
    } catch (err) { alert("Update failed"); }
  };

  const handleDelete = async (id) => {
    if (window.confirm("Kyan aap ise delete karna chahte hain?")) {
      try {
        const endpoint = postType === 'job' ? 'jobs' : 'blog';
        await axios.delete(`http://localhost:5001/api/admin/${endpoint}/${id}`);
        fetchItems();
        alert("Deleted!");
      } catch (err) { alert("Delete Failed"); }
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      let response;
      if (postType === 'job') {
        response = await axios.post('http://localhost:5001/api/admin/jobs', formData);
      } else {
        const data = new FormData();
        data.append('category', category); 
        data.append('title', formData.title);
        data.append('description', formData.description);
        if (file) data.append('image', file);
        response = await axios.post('http://localhost:5001/api/admin/blog', data);
      }
      if (response.status === 201) {
        alert("Published Successfully!");
        setFormData({ title: '', description: '', loc: '', salary: '', type: 'On-site' });
        setFile(null);
        e.target.reset();
      }
    } catch (err) { alert("Error publishing content"); }
  };

  return (
    <div className="flex min-h-screen bg-gray-50 pt-10 font-sans">

      {/* SIDEBAR - Spacing fixed for Brand Name */}
      <div className="w-80 bg-black text-white p-8 fixed h-full shadow-2xl overflow-y-auto">
        <div className="mt-16 mb-12"> {/* mt-16 fixes the overlap */}
          <h2 className="text-2xl font-black text-orange-500 tracking-tighter leading-none">
            Rhodeotech <br /> 
            <span className="text-white text-4xl">ADMIN</span>
          </h2>
        </div>

        <div className="space-y-3">
          <button onClick={() => setActiveTab('create')} className={`w-full text-left p-4 rounded-2xl font-bold transition-all ${activeTab === 'create' ? 'bg-orange-600 shadow-lg shadow-orange-900/40' : 'text-gray-400 hover:text-white'}`}>➕ Create New</button>
          <button onClick={() => setActiveTab('manage')} className={`w-full text-left p-4 rounded-2xl font-bold transition-all ${activeTab === 'manage' ? 'bg-orange-600 shadow-lg shadow-orange-900/40' : 'text-gray-400 hover:text-white'}`}>⚙️ Manage All</button>
          <button onClick={() => setActiveTab('inquiries')} className={`w-full text-left p-4 rounded-2xl font-bold transition-all ${activeTab === 'inquiries' ? 'bg-orange-600 shadow-lg shadow-orange-900/40' : 'text-gray-400 hover:text-white'}`}>📩 Inquiries</button>
        </div>

        {(activeTab === 'create' || activeTab === 'manage') && (
          <div className="mt-10 border-t border-gray-800 pt-6 space-y-6">
             <div className="flex bg-gray-900 p-1.5 rounded-xl border border-gray-800">
               <button onClick={() => setPostType('job')} className={`flex-1 py-2.5 rounded-lg text-[10px] font-black uppercase tracking-[0.2em] transition-all ${postType === 'job' ? 'bg-white text-black' : 'text-gray-500 hover:text-gray-300'}`}>Jobs</button>
               <button onClick={() => setPostType('blog')} className={`flex-1 py-2.5 rounded-lg text-[10px] font-black uppercase tracking-[0.2em] transition-all ${postType === 'blog' ? 'bg-white text-black' : 'text-gray-500 hover:text-gray-300'}`}>Blogs</button>
             </div>

             {postType === 'blog' && (
               <div className="space-y-3 animate-in fade-in slide-in-from-top-2">
                 <p className="text-[10px] font-black text-gray-500 uppercase tracking-[0.3em] ml-2">Industry Sector</p>
                 <select value={category} onChange={(e) => setCategory(e.target.value)} className="w-full bg-gray-900 text-white p-4 rounded-xl text-sm outline-none border border-gray-800 focus:border-orange-600 transition-all">
                   <option value="Electronics">Electronics</option>
                   <option value="Electrical">Electrical</option>
                   <option value="Chemical">Chemical</option>
                   <option value="Industries">Industries</option>
                 </select>
               </div>
             )}
          </div>
        )}
      </div>

      {/* MAIN CONTENT AREA */}
      <div className="flex-1 ml-80 p-12">

        {/* TAB: CREATE CONTENT */}
        {activeTab === 'create' && (
          <div className="max-w-3xl bg-white rounded-[3rem] p-12 shadow-sm border border-gray-100">
            <div className="mb-10">
              <span className="text-orange-600 font-black text-[10px] uppercase tracking-[0.3em]">{postType} engine</span>
              <h1 className="text-5xl font-black italic tracking-tighter text-gray-900">Add Content</h1>
            </div>

            <form onSubmit={handleSubmit} className="space-y-5">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-4">Entry Title</label>
                <input required className="w-full p-5 bg-gray-50 rounded-2xl font-bold border border-transparent focus:bg-white focus:border-orange-500 outline-none transition-all" placeholder="Enter title..." value={formData.title} onChange={e => setFormData({...formData, title: e.target.value})} />
              </div>

              {postType === 'blog' ? (
                <>
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-4">Blog Narrative</label>
                    <textarea rows="6" className="w-full p-5 bg-gray-50 rounded-2xl font-bold border border-transparent focus:bg-white focus:border-orange-500 outline-none transition-all" placeholder="Write content here..." value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} />
                  </div>
                  <div className="p-8 border-2 border-dashed border-gray-200 rounded-[2rem] bg-gray-50/30 hover:bg-orange-50/30 transition-all text-center">
                    <input type="file" onChange={(e) => setFile(e.target.files[0])} className="text-xs font-bold" />
                  </div>
                </>
              ) : (
                <div className="grid grid-cols-2 gap-5">
                  <input className="w-full p-5 bg-gray-50 rounded-2xl font-bold border border-transparent focus:border-orange-500 outline-none transition-all" placeholder="Location" value={formData.loc} onChange={e => setFormData({...formData, loc: e.target.value})} />
                  <input className="w-full p-5 bg-gray-50 rounded-2xl font-bold border border-transparent focus:border-orange-500 outline-none transition-all" placeholder="Salary" value={formData.salary} onChange={e => setFormData({...formData, salary: e.target.value})} />
                </div>
              )}
              <button className="w-full bg-black text-white py-6 rounded-[2rem] font-black text-xl hover:bg-orange-600 transition-all shadow-2xl transform hover:-translate-y-1 uppercase">Publish Now</button>
            </form>
          </div>
        )}

        {/* TAB: MANAGE CONTENT */}
        {activeTab === 'manage' && (
          <div className="max-w-4xl bg-white rounded-[3rem] p-12 shadow-sm border border-gray-100">
            <h1 className="text-4xl font-black italic text-gray-900 tracking-tighter mb-10">Active Repository</h1>
            <div className="space-y-4">
              {items.length > 0 ? items.map(item => (
                <div key={item._id} className="flex items-center justify-between p-7 bg-gray-50 rounded-[2.5rem] border border-gray-100">
                  <div>
                    <h3 className="font-black text-xl text-gray-800">{item.title}</h3>
                    <span className="text-orange-500 text-[10px] font-black uppercase tracking-widest">{item.loc || item.category}</span>
                  </div>
                  <div className="flex gap-3">
                    <button onClick={() => { setEditData(item); setIsEditing(true); }} className="bg-white border border-gray-200 px-6 py-2 rounded-xl font-black text-[10px] tracking-widest hover:bg-black hover:text-white transition-all">EDIT</button>
                    <button onClick={() => handleDelete(item._id)} className="bg-red-50 text-red-500 px-6 py-2 rounded-xl font-black text-[10px] tracking-widest hover:bg-red-600 hover:text-white transition-all">DELETE</button>
                  </div>
                </div>
              )) : <p className="text-center py-10 text-gray-400 font-bold italic uppercase">No content found.</p>}
            </div>
          </div>
        )}

        {/* TAB: INQUIRIES DISPLAY - NEW SECTION */}
        {activeTab === 'inquiries' && (
          <div className="max-w-5xl bg-white rounded-[3rem] p-12 shadow-sm border border-gray-100">
            <div className="mb-10">
              <span className="text-orange-600 font-black text-[10px] uppercase tracking-[0.3em]">Customer Requests</span>
              <h1 className="text-5xl font-black italic tracking-tighter text-gray-900">Contact Inquiries</h1>
            </div>

            <div className="grid gap-6">
              {inquiries.length > 0 ? inquiries.map((iq) => (
                <div key={iq._id} className="p-8 bg-gray-50 rounded-[2.5rem] border border-gray-100 hover:shadow-xl transition-all">
                  <div className="flex justify-between items-start mb-4">
                    <div>
                      <h3 className="text-2xl font-black text-gray-900">{iq.fullName}</h3>
                      <p className="text-orange-600 font-bold text-sm tracking-tight">{iq.email}</p>
                    </div>
                    <span className="bg-white px-5 py-2 rounded-full text-[10px] font-black uppercase tracking-widest border border-gray-200 shadow-sm">
                      {iq.sector || 'General Inquiry'}
                    </span>
                  </div>
                  <div className="bg-white p-7 rounded-3xl border border-gray-100 mb-5">
                    <p className="text-gray-600 font-medium leading-relaxed italic">"{iq.message}"</p>
                  </div>
                  <div className="flex justify-between items-center px-2">
                    <div className="flex gap-6">
                      <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Company: <span className="text-gray-900">{iq.company || 'N/A'}</span></p>
                    </div>
                    <p className="text-[9px] font-bold text-gray-300 uppercase tracking-widest">{new Date(iq.createdAt).toLocaleDateString()}</p>
                  </div>
                </div>
              )) : <p className="text-center py-20 text-gray-300 font-bold uppercase italic">No inquiries in the database.</p>}
            </div>
          </div>
        )}
      </div>

      {/* EDIT MODAL */}
      {isEditing && editData && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-xl z-[200] flex items-center justify-center p-6">
          <div className="bg-white w-full max-w-2xl rounded-[4rem] p-12 relative">
            <button onClick={() => setIsEditing(false)} className="absolute top-10 right-10 text-3xl font-light hover:text-orange-600 transition-all">✕</button>
            <h2 className="text-4xl font-black mb-10 italic tracking-tighter">Modify Entry</h2>
            <form onSubmit={handleUpdate} className="space-y-5">
              <input className="w-full p-5 bg-gray-50 rounded-2xl font-bold border border-gray-100 outline-none" value={editData.title} onChange={e => setEditData({...editData, title: e.target.value})} />
              {postType === 'blog' ? (
                <textarea rows="6" className="w-full p-5 bg-gray-50 rounded-2xl font-bold border border-gray-100 outline-none" value={editData.description} onChange={e => setEditData({...editData, description: e.target.value})} />
              ) : (
                <div className="grid grid-cols-2 gap-5">
                  <input className="w-full p-5 bg-gray-50 rounded-2xl font-bold border border-gray-100 outline-none" value={editData.loc} onChange={e => setEditData({...editData, loc: e.target.value})} />
                  <input className="w-full p-5 bg-gray-50 rounded-2xl font-bold border border-gray-100 outline-none" value={editData.salary} onChange={e => setEditData({...editData, salary: e.target.value})} />
                </div>
              )}
              <button type="submit" className="w-full bg-orange-600 text-white py-6 rounded-3xl font-black text-xl shadow-2xl">COMMIT CHANGES</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminPanel;
